import javax.inject._
import play.api.mvc._
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.{ExecutionContext, Future}
import play.api.libs.json.Json

case class Product(id: Int, name: String, price: Double)

@Singleton
class ProductsController @Inject()(cc: ControllerComponents)(implicit ec: ExecutionContext)
  extends AbstractController(cc) {

  def search = Action.async { request =>
    val nameFilter = request.queryString.get("name").map(_.head).map(name => s"name LIKE '%$name%'")
    val priceMinFilter = request.queryString.get("price_min").map(_.head).map(min => s"price >= $min")
    val priceMaxFilter = request.queryString.get("price_max").map(_.head).map(max => s"price <= $max")

    val whereClauses = List(nameFilter, priceMinFilter, priceMaxFilter).flatten

    val sqlFragment = whereClauses match {
      case Nil => sql""
      case _ => sql"WHERE " ++ Fragments.joinSqlFragments(whereClauses.map(sql"$_"))
    }

    val query = sql"SELECT * FROM products $sqlFragment".as[Product]

    db.run(query).map { products =>
      Ok(Json.toJson(products))
    }
  }

  // Assuming you have a database connection setup
  lazy val db: Database = Database.forConfig("mydb")
}